sql:
SELECT item_type_name 
FROM item_types 
WHERE item_type_name NOT IN (SELECT DISTINCT item_type FROM tasks);

SELECT U.user_name, T.item_name, T.due_date
FROM tasks T
INNER JOIN users U ON T.assigned_to_id = U.user_id;

SELECT * 
FROM notifications 
WHERE notification_id = 2;

external_knowledge:
- 'treasures' refers to the tasks;
- 'realm of Procurement' refers to the department 'Procurement';
- 'active managers' refers to users with status 'active' and role 'manager';
- 'whispers (notes)' refer to the additional notes or details about the task;
- 'weight (priority)' refers to the priority level of the task;
- 'vigilant overseers (managers)' refers to the managers assigned to the tasks.

- 'urgent tasks' refers to tasks where the `item_name` includes the word 'urgent';
- 'completed past their deadlines' indicates that these tasks were completed later than their due dates;
- 'stock information about the task's item' relates to the quantity and reorder level of the item, if available in the inventory.

sql:
SELECT task_id, item_name, completed, priority
FROM tasks
WHERE completed = 1 OR priority = 'High';
